import elasticsearch
from elasticsearch import Elasticsearch

es = Elasticsearch(['localhost:9200'])

# Index a document
doc = {
    "title": "My First Document",
    "content": "This is my first document!"
}
es.index(index='my-index', doc_type='my-type', body=doc)

# Search for documents
query = {
    "query": {
        "match": {
            "title": "My First Document"
        }
    }
}
results = es.search(index='my-index', body=query)
print(results['hits']['hits'])

# Aggregate logs
logs = [
    {"message": "This is a log message", "level": "info"},
    {"message": "This is another log message", "level": "warning"}
]
es.bulk(index='my-index', body=logs)